/**
 * 人物关系图可视化
 * 使用 graphology 实现力导向图
 * 节点：人物，边：人物关系
 * 支持点击查看详情
 */

import { useEffect, useRef, useState } from 'react'
import { Card, Button, Space, message, Spin, Drawer, Descriptions, Tag } from 'antd'
import { ReloadOutlined } from '@ant-design/icons'
import Graph from 'graphology'
import forceAtlas2 from 'graphology-layout-forceatlas2'

interface GraphNode {
  id: string
  label: string
  mbti?: string
  type?: string
}

interface RawRelationship {
  from: string
  to: string
  type: string
  strength: number
  development?: unknown[]
}

interface GraphEdge {
  id: string
  source: string
  target: string
  label: string
  weight: number
  from: string
  to: string
  type: string
  strength: number
}

interface CharacterGraphProps {
  projectRoot: string | null
  onNodeClick?: (characterName: string) => void
}

const REL_TYPE_COLORS: Record<string, string> = {
  mentor: '#1677ff',
  rival: '#ff4d4f',
  love: '#eb2f96',
  family: '#52c41a',
  friend: '#13c2c2',
  master: '#722ed1',
  enemy: '#d4380d',
}

const CharacterGraph: React.FC<CharacterGraphProps> = ({ projectRoot }) => {
  const [loading, setLoading] = useState(false)
  const [graphData, setGraphData] = useState<{
    nodes: GraphNode[]
    edges: GraphEdge[]
  } | null>(null)
  const [selectedNode, setSelectedNode] = useState<GraphNode | null>(null)
  const [drawerVisible, setDrawerVisible] = useState(false)

  const loadGraphData = async () => {
    if (!projectRoot) return
    setLoading(true)
    try {
      // 读取 relationships.yaml
      const relFile = `${projectRoot}/relationships.yaml`
      const relResult = await window.electronAPI.yaml.read(relFile)
      const relData = relResult.success
        ? (relResult.data as Record<string, unknown>)
        : { relationships: [] }
      const rels = (relData.relationships as RawRelationship[]) || []

      // 读取角色基本信息
      const charsDir = `${projectRoot}/characters`
      const charFilesResult = await window.electronAPI.readdir(charsDir)
      if (!charFilesResult.success) { console.error('读取characters目录失败:', charFilesResult.error); }
      const charFiles = charFilesResult.data || []
      const charInfoMap: Record<string, GraphNode> = {}

      for (const file of charFiles) {
        if (file.isFile && file.name.endsWith('.yaml')) {
          const charResult = await window.electronAPI.yaml.read(`${charsDir}/${file.name}`)
          if (charResult.success && charResult.data) {
            const data = charResult.data as Record<string, unknown>
            const name = String(data.name || file.name.replace('.yaml', ''))
            charInfoMap[name] = {
              id: name,
              label: name,
              mbti: data.mbti as string | undefined,
              type: 'character',
            }
          }
        }
      }

      // 构建节点（所有出现在关系中的角色）
      const nodeSet = new Set<string>()
      for (const rel of rels) {
        nodeSet.add(rel.from)
        nodeSet.add(rel.to)
      }

      const nodes: GraphNode[] = Array.from(nodeSet).map(name => {
        const info = charInfoMap[name] || {}
        return {
          id: name,
          label: name,
          mbti: info.mbti,
          type: info.type,
        }
      })

      const edges: GraphEdge[] = rels.map((rel: RawRelationship, idx: number) => ({
        id: `edge-${idx}`,
        source: String(rel.from || ''),
        target: String(rel.to || ''),
        from: String(rel.from || ''),
        to: String(rel.to || ''),
        label: String(rel.type || ''),
        type: String(rel.type || ''),
        weight: (rel.strength as number) || 0.5,
        strength: (rel.strength as number) || 0.5,
      }))

      setGraphData({ nodes, edges })
    } catch (error) {
      console.error('加载关系图失败:', error)
      message.error('加载关系图失败')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    loadGraphData()
  }, [projectRoot])

  const handleNodeClick = (nodeId: string) => {
    const node = graphData?.nodes.find(n => n.id === nodeId)
    if (node) {
      setSelectedNode(node)
      setDrawerVisible(true)
    }
  }

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先打开一个小说项目
      </div>
    )
  }

  if (loading) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <Spin tip="加载关系图..." />
      </div>
    )
  }

  if (!graphData || graphData.nodes.length === 0) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <div style={{ color: '#999', marginBottom: 16 }}>
          暂无人物关系数据
        </div>
        <Button icon={<ReloadOutlined />} onClick={loadGraphData}>
          刷新
        </Button>
      </div>
    )
  }

  // 简单的 SVG 力导向图实现
  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      <div
        style={{
          padding: '8px 16px',
          borderBottom: '1px solid #e8e8e8',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
        }}
      >
        <span style={{ fontSize: 13 }}>
          人物关系图 · {graphData.nodes.length} 人 / {graphData.edges.length} 条关系
        </span>
        <Space>
          <Button size="small" icon={<ReloadOutlined />} onClick={loadGraphData}>
            刷新
          </Button>
        </Space>
      </div>

      <ForceGraph
        nodes={graphData.nodes}
        edges={graphData.edges}
        onNodeClick={handleNodeClick}
      />

      <Drawer
        title={selectedNode?.label}
        open={drawerVisible}
        onClose={() => setDrawerVisible(false)}
        width={300}
      >
        {selectedNode && (
          <Descriptions column={1} size="small">
            <Descriptions.Item label="名称">{selectedNode.label}</Descriptions.Item>
            {selectedNode.mbti && (
              <Descriptions.Item label="MBTI">
                <Tag color="purple">{selectedNode.mbti}</Tag>
              </Descriptions.Item>
            )}
            <Descriptions.Item label="相关关系">
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                {graphData?.edges
                  .filter(e => e.source === selectedNode.id || e.target === selectedNode.id)
                  .map((edge, idx) => {
                    const other = edge.source === selectedNode.id ? edge.target : edge.source
                    return (
                      <Tag
                        key={idx}
                        color={REL_TYPE_COLORS[edge.label] || 'default'}
                      >
                        {other} ({edge.label})
                      </Tag>
                    )
                  })}
              </div>
            </Descriptions.Item>
          </Descriptions>
        )}
      </Drawer>
    </div>
  )
}

// 简单的 SVG 力导向图组件
interface ForceGraphProps {
  nodes: GraphNode[]
  edges: GraphEdge[]
  onNodeClick: (nodeId: string) => void
}

const ForceGraph: React.FC<ForceGraphProps> = ({ nodes, edges, onNodeClick }) => {
  const containerRef = useRef<HTMLDivElement>(null)
  const [positions, setPositions] = useState<Record<string, { x: number; y: number }>>({})
  const [dragging, setDragging] = useState<string | null>(null)

  // 初始化力导向布局
  useEffect(() => {
    if (nodes.length === 0) return

    const graph = new Graph()

    // 添加节点
    for (const node of nodes) {
      graph.addNode(node.id, {
        label: node.label,
        x: Math.random() * 400 + 100,
        y: Math.random() * 300 + 100,
        size: 20,
        color: '#1890ff',
      })
    }

    // 添加边
    for (const edge of edges) {
      if (graph.hasNode(edge.source) && graph.hasNode(edge.target)) {
        try {
          graph.addEdge(edge.source, edge.target, {
            label: edge.label,
            size: edge.weight * 3 + 1,
            color: REL_TYPE_COLORS[edge.label] || '#999',
          })
        } catch {
          // 边已存在则跳过
        }
      }
    }

    // 运行 ForceAtlas2
    if (graph.order > 0) {
      try {
        forceAtlas2.assign(graph, {
          iterations: 100,
          settings: {
            gravity: 1,
            scalingRatio: 10,
            strongGravityMode: true,
          },
        })
      } catch (e) {
        console.warn('ForceAtlas2 布局失败，使用随机位置:', e)
      }
    }

    // 提取位置
    const pos: Record<string, { x: number; y: number }> = {}
    graph.forEachNode((nodeId, attrs) => {
      pos[nodeId] = { x: (attrs.x as number) || 0, y: (attrs.y as number) || 0 }
    })

    setPositions(pos)
  }, [nodes, edges])

  if (nodes.length === 0) return null

  // 计算 bounds
  const posValues = Object.values(positions)
  if (posValues.length === 0) return null

  const minX = Math.min(...posValues.map(p => p.x))
  const maxX = Math.max(...posValues.map(p => p.x))
  const minY = Math.min(...posValues.map(p => p.y))
  const maxY = Math.max(...posValues.map(p => p.y))
  const rangeX = maxX - minX || 1
  const rangeY = maxY - minY || 1

  const width = 500
  const height = 400
  const padding = 40
  const scaleX = (width - 2 * padding) / rangeX
  const scaleY = (height - 2 * padding) / rangeY

  const getX = (x: number) => (x - minX) * scaleX + padding
  const getY = (y: number) => (y - minY) * scaleY + padding

  return (
    <div
      ref={containerRef}
      style={{ flex: 1, overflow: 'auto', background: '#fafafa' }}
    >
      <svg width={width} height={height} style={{ cursor: 'grab' }}>
        {/* 绘制边 */}
        {edges.map(edge => {
          const fromPos = positions[edge.source]
          const toPos = positions[edge.target]
          if (!fromPos || !toPos) return null

          const x1 = getX(fromPos.x)
          const y1 = getY(fromPos.y)
          const x2 = getX(toPos.x)
          const y2 = getY(toPos.y)

          // 计算边的中点（用于放置标签）
          const midX = (x1 + x2) / 2
          const midY = (y1 + y2) / 2

          return (
            <g key={edge.id}>
              <line
                x1={x1}
                y1={y1}
                x2={x2}
                y2={y2}
                stroke={REL_TYPE_COLORS[edge.label] || '#999'}
                strokeWidth={Math.max(edge.weight * 3 + 1, 1)}
                strokeOpacity={0.6}
              />
              <text
                x={midX}
                y={midY - 5}
                textAnchor="middle"
                fontSize={10}
                fill={REL_TYPE_COLORS[edge.label] || '#999'}
                style={{ pointerEvents: 'none' }}
              >
                {edge.label}
              </text>
            </g>
          )
        })}

        {/* 绘制节点 */}
        {nodes.map(node => {
          const pos = positions[node.id]
          if (!pos) return null

          const cx = getX(pos.x)
          const cy = getY(pos.y)

          return (
            <g
              key={node.id}
              style={{ cursor: 'pointer' }}
              onClick={() => onNodeClick(node.id)}
            >
              <circle
                cx={cx}
                cy={cy}
                r={16}
                fill="#1890ff"
                stroke="#fff"
                strokeWidth={2}
              />
              <text
                x={cx}
                y={cy + 4}
                textAnchor="middle"
                fontSize={11}
                fill="#fff"
                style={{ pointerEvents: 'none', fontWeight: 'bold' }}
              >
                {node.label.slice(0, 2)}
              </text>
              <text
                x={cx}
                y={cy - 22}
                textAnchor="middle"
                fontSize={11}
                fill="#333"
                style={{ pointerEvents: 'none' }}
              >
                {node.label}
              </text>
            </g>
          )
        })}
      </svg>

      {/* 图例 */}
      <div
        style={{
          padding: '8px 16px',
          fontSize: 11,
          color: '#666',
          borderTop: '1px solid #e8e8e8',
          display: 'flex',
          gap: 12,
          flexWrap: 'wrap',
        }}
      >
        {Object.entries(REL_TYPE_COLORS).map(([type, color]) => (
          <span key={type} style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            <span
              style={{
                display: 'inline-block',
                width: 16,
                height: 2,
                background: color,
              }}
            />
            {type}
          </span>
        ))}
      </div>
    </div>
  )
}

export default CharacterGraph

/**
 * 导出管理器
 * 支持 Markdown 和 EPUB 格式导出
 */

import path from 'path'

import { useState } from 'react'
import {
  Button,
  Space,
  Modal,
  Form,
  Select,
  Switch,
  message,
  Progress,
  Alert,
  Radio,
  Divider,
  List,
  Card,
  Tag,
  Input,
} from 'antd'
import {
  DownloadOutlined,
  FileMarkdownOutlined,
  BookOutlined,
  CheckCircleOutlined,
  FolderOpenOutlined,
} from '@ant-design/icons'

interface ExportManagerProps {
  projectRoot: string | null
  projectName?: string
  visible: boolean
  onClose: () => void
}

interface ChapterInfo {
  path: string
  name: string
  volume: string
  order: number
  content?: string
}

interface ExportProgress {
  current: number
  total: number
  status: 'idle' | 'exporting' | 'done' | 'error'
  message: string
}

const ExportManager: React.FC<ExportManagerProps> = ({
  projectRoot,
  projectName = '小说',
  visible,
  onClose,
}) => {
  const [exportFormat, setExportFormat] = useState<'markdown' | 'epub'>('markdown')
  const [exportMode, setExportMode] = useState<'single' | 'byVolume'>('single')
  const [includeToc, setIncludeToc] = useState(true)
  const [progress, setProgress] = useState<ExportProgress>({
    current: 0,
    total: 0,
    status: 'idle',
    message: '',
  })
  const [exportPath, setExportPath] = useState<string | null>(null)

  // 加载所有章节
  const loadChapters = async (): Promise<ChapterInfo[]> => {
    if (!projectRoot) return []

    const chapters: ChapterInfo[] = []

    const readDir = async (dirPath: string, volumeName: string = '正文') => {
      try {
        const entriesResult = await window.electronAPI.readdir(dirPath)
        if (!entriesResult.success) { console.warn('读取目录失败:', dirPath, entriesResult.error); return; }
        const entries = entriesResult.data || []
        for (const entry of entries) {
          const fullPath = `${dirPath}/${entry.name}`
          if (entry.isDirectory) {
            await readDir(fullPath, entry.name)
          } else if (entry.isFile && entry.name.endsWith('.md') && !entry.name.startsWith('_')) {
            const contentResult = await window.electronAPI.readFile(fullPath)
            if (contentResult.success && contentResult.content) {
              // 提取章节序号
              const orderMatch = entry.name.match(/第(\d+)章/)
              chapters.push({
                path: fullPath,
                name: entry.name.replace('.md', ''),
                volume: volumeName,
                order: orderMatch ? parseInt(orderMatch[1]) : 0,
                content: contentResult.content,
              })
            }
          }
        }
      } catch (e) {
        console.warn('读取目录失败:', dirPath, e)
      }
    }

    const plotsDir = `${projectRoot}/plots`
    const existsResult = await window.electronAPI.exists(plotsDir)
    if (existsResult && existsResult.success && existsResult.exists) {
      await readDir(plotsDir)
    }

    return chapters.sort((a, b) => {
      if (a.volume !== b.volume) return a.volume.localeCompare(b.volume)
      return a.order - b.order
    })
  }

  // 导出 Markdown
  const exportMarkdown = async () => {
    if (!projectRoot) return

    setProgress({ current: 0, total: 0, status: 'exporting', message: '加载章节...' })

    try {
      const chapters = await loadChapters()
      if (chapters.length === 0) {
        message.warning('没有找到可导出的章节')
        setProgress({ current: 0, total: 0, status: 'error', message: '没有找到章节' })
        return
      }

      // 读取 project.yaml 获取标题
      let title = projectName
      try {
        const projectResult = await window.electronAPI.yaml.read(`${projectRoot}/project.yaml`)
        if (projectResult.success && projectResult.data) {
          const data = projectResult.data as Record<string, unknown>
          if (data.title) title = String(data.title)
        }
      } catch {}

      setProgress({ current: 0, total: chapters.length, status: 'exporting', message: '正在导出...' })

      if (exportMode === 'single') {
        // 单文件导出
        let toc = ''
        if (includeToc) {
          toc = `# ${title}\n\n`
          toc += `> 导出时间：${new Date().toLocaleString()}\n\n`
          toc += `## 目录\n\n`
          const volumes = [...new Set(chapters.map(c => c.volume))]
          for (const vol of volumes) {
            toc += `### ${vol}\n\n`
            const volChapters = chapters.filter(c => c.volume === vol)
            for (const ch of volChapters) {
              toc += `- [${ch.name}](#${ch.name.replace(/\s/g, '-')})\n`
            }
            toc += '\n'
          }
          toc += '---\n\n'
        }

        let fullContent = toc

        // 按卷分组
        const volumes = [...new Set(chapters.map(c => c.volume))]
        for (const vol of volumes) {
          fullContent += `\n\n# ${vol}\n\n`
          const volChapters = chapters.filter(c => c.volume === vol)

          for (let i = 0; i < volChapters.length; i++) {
            const ch = volChapters[i]
            setProgress({
              current: i + 1,
              total: chapters.length,
              status: 'exporting',
              message: `正在处理: ${ch.name}`,
            })

            fullContent += `\n\n## ${ch.name}\n\n`
            fullContent += ch.content || ''
          }
        }

        // 选择导出位置
        const parentDir = await window.electronAPI.openDirectory()
        if (!parentDir || parentDir.trim() === '') {
          setProgress({ current: 0, total: 0, status: 'idle', message: '' })
          return
        }

        const exportFile = path.join(parentDir, `${title}.md`)
        try {
          const writeResult = await window.electronAPI.writeFile(exportFile, fullContent)
          if (!writeResult.success) throw new Error(writeResult.error || '写入失败')
          setExportPath(exportFile)
          setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: '导出完成' })
          message.success(`已导出到: ${exportFile}`)
        } catch (err) {
          message.error(`导出失败: ${(err as Error).message}`)
          setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
        }
      } else {
        // 按卷拆分导出
        const parentDir = await window.electronAPI.openDirectory()
        if (!parentDir) {
          setProgress({ current: 0, total: 0, status: 'idle', message: '' })
          return
        }

        const volumes = [...new Set(chapters.map(c => c.volume))]
        for (let vi = 0; vi < volumes.length; vi++) {
          const vol = volumes[vi]
          const volChapters = chapters.filter(c => c.volume === vol)

          let volContent = `# ${vol}\n\n`
          if (includeToc) {
            volContent += `## 目录\n\n`
            for (const ch of volChapters) {
              volContent += `- [${ch.name}](#${ch.name.replace(/\s/g, '-')})\n`
            }
            volContent += '\n---\n\n'
          }

          for (let ci = 0; ci < volChapters.length; ci++) {
            const ch = volChapters[ci]
            setProgress({
              current: vi * volChapters.length + ci + 1,
              total: chapters.length,
              status: 'exporting',
              message: `正在处理: ${vol}/${ch.name}`,
            })

            volContent += `\n\n## ${ch.name}\n\n`
            volContent += ch.content || ''
          }

          const exportFile = `${parentDir}/${vol}.md`
          await window.electronAPI.writeFile(exportFile, volContent)
        }

        setExportPath(parentDir)
        setProgress({ current: chapters.length, total: chapters.length, status: 'done', message: '导出完成' })
        message.success(`已导出 ${volumes.length} 个文件到: ${parentDir}`)
      }
    } catch (error) {
      message.error('导出失败')
      setProgress({ current: 0, total: 0, status: 'error', message: '导出失败' })
    }
  }

  // 简单 HTML 转义
  const escapeHtml = (str: string): string => {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;')
  }

  // 转换为 EPUB XHTML
  const markdownToXhtml = (md: string, chapterTitle: string): string => {
    // 简单转换：处理标题和段落
    let html = md
      .replace(/^### (.+)$/gm, '<h3>$1</h3>')
      .replace(/^## (.+)$/gm, '<h2>$1</h2>')
      .replace(/^# (.+)$/gm, '<h1>$1</h1>')
      .replace(/\n\n/g, '</p><p>')
      .replace(/\n/g, '<br/>')

    return `<?xml version="1.0" encoding="UTF-8"?>
<html xmlns="http://www.w3.org/1999/xhtml">
<head>
  <title>${escapeHtml(chapterTitle)}</title>
  <style>
    body { font-family: "SimSun", serif; font-size: 1em; line-height: 1.6; margin: 1em; }
    h1, h2, h3 { text-align: center; margin: 1em 0; }
    p { text-indent: 2em; margin: 0.5em 0; }
  </style>
</head>
<body>
  <h1>${escapeHtml(chapterTitle)}</h1>
  <p>${html}</p>
</body>
</html>`
  }

  // 生成 EPUB
  const exportEpub = async () => {
    if (!projectRoot) return

    setProgress({ current: 0, total: 0, status: 'exporting', message: '加载章节...' })

    try {
      const chapters = await loadChapters()
      if (chapters.length === 0) {
        message.warning('没有找到可导出的章节')
        setProgress({ current: 0, total: 0, status: 'error', message: '没有找到章节' })
        return
      }

      // 读取 project.yaml
      let title = projectName
      let author = '未知作者'
      try {
        const projectResult = await window.electronAPI.yaml.read(`${projectRoot}/project.yaml`)
        if (projectResult.success && projectResult.data) {
          const data = projectResult.data as Record<string, unknown>
          if (data.title) title = String(data.title)
          if (data.author) author = String(data.author)
        }
      } catch {}

      // 选择导出位置
      const parentDir = await window.electronAPI.openDirectory()
      if (!parentDir) {
        setProgress({ current: 0, total: 0, status: 'idle', message: '' })
        return
      }

      const safeTitle = title.replace(/[^\w\u4e00-\u9fa5]/g, '_')
      const epubDir = `${parentDir}/${safeTitle}_epub`
      const metaResult = await window.electronAPI.mkdir(`${epubDir}/META-INF`)
      if (!metaResult.success) { throw new Error(metaResult.error || '创建META-INF失败') }
      const chaptersResult = await window.electronAPI.mkdir(`${epubDir}/OEBPS/chapters`)
      if (!chaptersResult.success) { throw new Error(chaptersResult.error || '创建OEBPS/chapters失败') }

      // mimetype（不压缩）
      await window.electronAPI.writeFile(`${epubDir}/mimetype`, 'application/epub+zip')

      // container.xml
